// Calculate date range: last 7 days with 2-day lag
const now = new Date();
const endDate = new Date(now.getTime() - 2 * 24 * 60 * 60 * 1000);
const startDate = new Date(endDate.getTime() - 7 * 24 * 60 * 60 * 1000);

return [{ json: {
  startDate: startDate.toISOString().split('T')[0],
  endDate: endDate.toISOString().split('T')[0],
  reportDate: now.toISOString().split('T')[0]
}}];

// Find quick wins: position 4-20, impressions >= 10
const rows = $input.first().json.rows || [];
const reportDate = $('Calculate Date Range').first().json.reportDate;

const quickWins = [];
for (const row of rows) {
  const query = row.keys[0];
  const page = row.keys[1];
  const position = row.position || 0;
  const impressions = row.impressions || 0;
  const clicks = row.clicks || 0;
  const ctr = row.ctr || 0;

  if (position >= 4 && position <= 20 && impressions >= 10) {
    // Potential score: higher impressions + closer to position 1 = more potential
    const potentialScore = Math.round(impressions * (21 - position) * 100) / 100;
    quickWins.push({
      query,
      page,
      position: Math.round(position * 10) / 10,
      impressions,
      clicks,
      ctr: Math.round(ctr * 10000) / 100,
      potential_score: potentialScore
    });
  }
}

// Sort by potential_score descending, take top 25
quickWins.sort((a, b) => b.potential_score - a.potential_score);
const top25 = quickWins.slice(0, 25);

return [{ json: { opportunities: top25, totalFound: quickWins.length, reportDate } }];

// Build HTML email report of ranking opportunities
const opps = $json.opportunities || [];
const totalFound = $json.totalFound || 0;
const reportDate = $json.reportDate;

if (opps.length === 0) {
  return [{ json: { skipEmail: true } }];
}

let tableRows = '';
for (let i = 0; i < opps.length; i++) {
  const o = opps[i];
  const bg = i % 2 === 0 ? '#f9f9f9' : '#ffffff';
  // Highlight positions 4-10 (page 1) differently from 11-20 (page 2)
  const posColor = o.position <= 10 ? '#2d5016' : '#666';
  const pagePath = o.page.replace('https://tgyardcare.com', '');
  tableRows += `<tr style="background:${bg}">
    <td style="padding:8px;border:1px solid #ddd">${i + 1}</td>
    <td style="padding:8px;border:1px solid #ddd">${o.query}</td>
    <td style="padding:8px;border:1px solid #ddd;color:${posColor};font-weight:bold;text-align:center">${o.position}</td>
    <td style="padding:8px;border:1px solid #ddd;text-align:center">${o.impressions}</td>
    <td style="padding:8px;border:1px solid #ddd;text-align:center">${o.clicks}</td>
    <td style="padding:8px;border:1px solid #ddd;text-align:center">${o.ctr}%</td>
    <td style="padding:8px;border:1px solid #ddd;font-size:12px">${pagePath}</td>
  </tr>`;
}

const html = `
<div style="font-family:Arial,sans-serif;max-width:900px;margin:0 auto">
  <h2 style="color:#2d5016">TG-99 Ranking Opportunity Report</h2>
  <p style="color:#666">Week ending ${reportDate} | ${totalFound} quick-win queries found, top 25 shown</p>
  <p>These queries rank between positions 4-20 with 10+ impressions. Optimizing existing pages for these terms could push them into top-3 positions.</p>
  <table style="border-collapse:collapse;width:100%;font-size:13px">
    <thead>
      <tr style="background:#2d5016;color:#fff">
        <th style="padding:8px;border:1px solid #ddd">#</th>
        <th style="padding:8px;border:1px solid #ddd">Query</th>
        <th style="padding:8px;border:1px solid #ddd">Position</th>
        <th style="padding:8px;border:1px solid #ddd">Impressions</th>
        <th style="padding:8px;border:1px solid #ddd">Clicks</th>
        <th style="padding:8px;border:1px solid #ddd">CTR</th>
        <th style="padding:8px;border:1px solid #ddd">Page</th>
      </tr>
    </thead>
    <tbody>${tableRows}</tbody>
  </table>
  <h3 style="margin-top:20px;color:#2d5016">Recommended Actions</h3>
  <ul style="color:#444">
    <li><strong>Position 4-10 (page 1):</strong> Add the query to page title/H1, improve content depth, add internal links</li>
    <li><strong>Position 11-20 (page 2):</strong> Consider dedicated content, build backlinks, optimize meta description for CTR</li>
  </ul>
  <p style="color:#888;font-size:12px;margin-top:16px">Potential Score = impressions * (21 - position). Higher = easier win with more impact.</p>
</div>`;

return [{ json: {
  skipEmail: false,
  to_email: 'totalguardllc@gmail.com',
  subject: `[TG-99] Ranking Opportunities - ${opps.length} Quick Wins (${reportDate})`,
  html_body: html,
  workflow_name: 'TG-99',
  email_type: 'report'
}}];
